try {
  // Support both envelope ($json.body) and flat ($json) delivery modes
  let body;
  if ($json.body !== undefined && $json.body !== null && typeof $json.body === 'object') {
    body = $json.body;
  } else if (typeof $json === 'object' && $json !== null && ($json.name !== undefined || $json.hour !== undefined)) {
    // Flat delivery: n8n merged body fields directly into $json
    body = $json;
  } else {
    body = $json.body;
  }

  // Check if body could be parsed at all
  if (body === undefined || body === null || typeof body !== 'object') {
    return [{ json: { valid: false, errorMessage: 'Request body could not be parsed. Ensure Content-Type is application/json and body is valid JSON.' } }];
  }

  const name = body.name;
  const hour = body.hour;

  // Validate name
  if (name === undefined || name === null || String(name).trim() === '') {
    return [{ json: { valid: false, errorMessage: 'Missing or empty required field: name' } }];
  }

  // Validate hour
  if (hour === undefined || hour === null) {
    return [{ json: { valid: false, errorMessage: 'Missing required field: hour' } }];
  }

  // Strict integer check: must be a JSON number type and an integer.
  // String values like '9' are explicitly rejected; clients must send a JSON number, not a string.
  if (typeof hour !== 'number' || !Number.isInteger(hour) || hour < 0 || hour > 23) {
    return [{ json: { valid: false, errorMessage: 'Invalid value for hour: must be a JSON number integer between 0 and 23 (not a string or float)' } }];
  }

  const hourNum = hour;

  // Determine greeting
  let period;
  if (hourNum >= 5 && hourNum < 12) {
    period = 'Morning';
  } else if (hourNum >= 12 && hourNum < 18) {
    period = 'Afternoon';
  } else {
    period = 'Evening';
  }

  const greeting = `Good ${period}, ${String(name).trim()}!`;
  return [{ json: { valid: true, greeting, name: String(name).trim(), hour: hourNum, period } }];

} catch (err) {
  return [{ json: { valid: false, errorMessage: 'Internal error during input validation: ' + (err.message || String(err)) } }];
}
